  )

  return <Breadcrumb.Root items={items} />
};

const Variant = () => {
  const items = useMemo<Breadcrumb.Item[]>(
    () => [
      { href: "/", label: "サイヤ人編" },
      { href: "/", label: "ナメック星編" },
      { href: "/", label: "人造人間編" },
      { href: "/", currentPage: true, label: "魔人ブウ編" },
    ],
    [],
  )

  return (
    <PropsTable variant="stack" rows={["plain", "underline"]}>
      {(_, row, key) => (
        <Breadcrumb.Root
          key={key}
          variant={row}
          aria-label={`Breadcrumb-${row}`}
          items={items}
        />
      )}
    </PropsTable>
  )
};

const Size = () => {
  const items = useMemo<Breadcrumb.Item[]>(
