          const descriptionCount = !description
            ? 0
            : isArray(description)
              ? description.length
              : 1

          col = Math.max(col, termCount + descriptionCount)
        })
      }

      return col
    }, [children, items])
    const computedChildren = useMemo(
      () =>
        items.map((props, index) => <DataListItem key={index} {...props} />),
      [items],
    )
