    defaultValue = "from",
    delay = 0,
    disabled,
    duration = 0.4,
    from,
    readOnly,
    rotate = 45,
    to,
    value: valueProp,
    onChange,
    onClick: onClickProp,
    ...rest
  }) => {
    const opacity = "var(--opacity)"
    const animate = useAnimation()
    const [value, setValue] = useControllableState<KeyframeIdent>({
      defaultValue,
      value: valueProp,
      onChange,
    })

    const onClick = useCallback(async () => {
      if (readOnly) return

      await animate.start({
        opacity: 0,
        rotate: `${rotate}deg`,
        transition: { delay, duration },
      })

      setValue((prev) => (prev === "from" ? "to" : "from"))

      await animate.start({
        opacity: "var(--opacity)",
        rotate: "0deg",
        transition: { duration },
      })
    }, [readOnly, animate, rotate, duration, delay, setValue])

    return (
      <motion.button
        type="button"
        data-disabled={dataAttr(disabled)}
        data-readonly={dataAttr(readOnly)}
        data-value={value}
        animate={animate}
        custom={{ rotate }}
        disabled={disabled}
        initial={{ opacity, rotate: "0deg" }}
        onClick={handlerAll(onClickProp, onClick)}
        {...rest}
      >
        {value === "from" ? from : to}
      </motion.button>
    )
  },
)(undefined, (props) => {
  const css = useInjectVarsIntoCss(props.css, { opacity: "opacity" })
  const rest = useInjectVarsIntoProps(props, { opacity: "opacity" })

  return { ...rest, css, opacity: "{opacity}" }
})

