export const createComboboxItem = (
  children: ReactNode,
  { Group, Label, Option }: CreateComboboxItemOptions,
) => {
  const validChildren = getValidChildren(children)

  return validChildren
    .filter(
      ({ type }) => isSomeElement(type, Option) || isSomeElement(type, Group),
