        const label = findChild(validChildren, Label)

        return {
          ...props,
          items: validChildren
            .filter(({ type }) => isSomeElement(type, Option))
            .map(({ props }) => ({ ...props, label: props.children })),
          label: label?.props.children ?? props.label,
        }
      }
    })
