const Dynamic = () => {
  const [index, setIndex] = useState(0)
  const [items, setItems] = useState<Tabs.Item[]>([
    { id: uuid(), panel: "Tab Content", tab: "Tab" },
    { id: uuid(), panel: "Tab Content", tab: "Tab" },
    { id: uuid(), panel: "Tab Content", tab: "Tab" },
  ])

  const onAddTab = () => {
    const nextItems = [
      ...items,
      { id: uuid(), panel: "Tab Content", tab: "Tab" },
    ]
    setItems(nextItems)
    setIndex(nextItems.length - 1)
  }

  const onRemoveTab = (id: string) => {
    const removeIndex = items.findIndex((item) => item.id === id)
    const nextItems = items.filter((item) => item.id !== id)

    setItems(nextItems)

    if (removeIndex < index) {
      setIndex(index - 1)
    } else if (removeIndex === index) {
      setIndex(Math.min(index, nextItems.length - 1))
    }
  }

  return (
    <Tabs.Root index={index} items={items} manual onChange={setIndex}>
      <Tabs.List>
        {items.map(({ id, tab }, index) => {
          const hasRemove = items.length > 1

          return (
            <Tabs.Tab key={id} index={index} transition="none">
              {tab}
              {hasRemove ? (
                <IconButton
                  as="span"
                  size="2xs"
                  variant="ghost"
                  aria-label="Remove Tab"
                  icon={<XIcon />}
                  role="button"
                  onClick={(ev) => {
                    ev.stopPropagation()
                    onRemoveTab(id!)
                  }}
                />
              ) : null}
            </Tabs.Tab>
          )
        })}

        <Button
          size="xs"
          variant="ghost"
          role="tab"
          startIcon={<PlusIcon />}
          onClick={onAddTab}
        >
          Add Tab
        </Button>
      </Tabs.List>

      {items.map(({ id, panel }, index) => (
        <Tabs.Panel key={id} index={index}>
          <Heading>
            {panel} {id}
          </Heading>

          <Text>index: {index}</Text>
          <Text>id: {id}</Text>
        </Tabs.Panel>
      ))}
    </Tabs.Root>
  )
};

