    (props = {}) => ({
      ...visuallyHiddenAttributes,
      ...ariaProps,
      ...dataProps,
      ...eventProps,
      id,
      form,
      type: "checkbox",
      name,
      checked,
      disabled,
      readOnly,
      required,
      value,
      ...props,
      ref: mergeRefs(inputRef, ref, props.ref),
      onChange: handlerAll(props.onChange, onChange),
    }),
    [
      ariaProps,
      checked,
      dataProps,
      disabled,
      eventProps,
      form,
      id,
      name,
      onChange,
      readOnly,
      ref,
      required,
      value,
    ],
