    (props = {}) => ({
      ...dataProps,
      type: "button",
      "aria-disabled": ariaAttr(!interactive),
      "aria-label": value?.toString() ?? t("Toggle button"),
      "aria-pressed": trulyChecked,
      "data-active": dataAttr(active),
      "data-checked": dataAttr(trulyChecked),
